  ('new-orleans-la', 'New Orleans', 'Gulf Coast', 'LA', 29.9511, -90.0715, ARRAY['city', 'foodie', 'nightlife', 'cultural']::text[], 'Creole, jazz, beignets, and balcony shadows — the most distinctive food city in America.', NULL, '[{"name":"French Quarter","description":"Iron-laced balconies, Bourbon and Royal Streets, Café du Monde."},{"name":"Frenchmen Street","description":"Live music every night without the Bourbon-Street frenzy."},{"name":"Garden District","description":"Walking tour through Greek Revival mansions and Lafayette Cemetery No. 1."}]'::jsonb, '{"flightFromOrigin":{"NYC":220,"CHI":200,"LAX":280,"SFO":320,"SEA":380},"lodgingPerNightUsd":200,"foodPerDayUsd":95,"activitiesPerDayUsd":30}'::jsonb, ARRAY['spring', 'fall', 'winter']::text[], NULL),
