  ('austin-tx', 'Austin', 'Texas Hill Country', 'TX', 30.2672, -97.7431, ARRAY['city', 'foodie', 'nightlife', 'scenic']::text[], 'Hill-country lakes, taco trailers, and live music seven nights a week.', NULL, '[{"name":"Franklin Barbecue","description":"Worth the line — at minimum once in your life."},{"name":"Barton Springs","description":"70°F spring-fed pool in Zilker Park, year-round."},{"name":"South Congress","description":"Vintage shops, food trailers, the boot store from every Austin photo."}]'::jsonb, '{"flightFromOrigin":{"NYC":260,"CHI":220,"LAX":240,"SFO":280,"SEA":320},"lodgingPerNightUsd":240,"foodPerDayUsd":75,"activitiesPerDayUsd":30}'::jsonb, ARRAY['spring', 'fall']::text[], NULL),
  ('asheville-nc', 'Asheville', 'Blue Ridge', 'NC', 35.5951, -82.5515, ARRAY['city', 'scenic', 'foodie', 'nature']::text[], 'Mountain town with America''s biggest house, a craft-brewery per capita rivaling Portland, and the Blue Ridge Parkway out the back door.', NULL, '[{"name":"Biltmore Estate","description":"America''s largest privately owned home; gardens are the move in spring."},{"name":"Blue Ridge Parkway","description":"Scenic drive immediately out of town — stop at Craggy Gardens."},{"name":"River Arts District","description":"Working-artist warehouses along the French Broad."}]'::jsonb, '{"flightFromOrigin":{"NYC":250,"CHI":240,"LAX":380,"SFO":410,"SEA":420},"lodgingPerNightUsd":220,"foodPerDayUsd":75,"activitiesPerDayUsd":35}'::jsonb, ARRAY['spring', 'fall']::text[], NULL),
  ('santa-fe-nm', 'Santa Fe', 'Southwest', 'NM', 35.687, -105.9378, ARRAY['cultural', 'scenic', 'foodie', 'chill']::text[], 'Adobe-walled art capital at 7,000 ft — green chile, Georgia O''Keeffe country, sunsets that feel staged.', NULL, '[{"name":"Canyon Road","description":"Half-mile of galleries and sculpture gardens."},{"name":"Meow Wolf","description":"Immersive art installation — book ahead."},{"name":"Tent Rocks","description":"45-minute drive; slot canyons and hoodoos in Kasha-Katuwe."}]'::jsonb, '{"flightFromOrigin":{"NYC":380,"CHI":320,"LAX":240,"SFO":260,"SEA":320},"lodgingPerNightUsd":230,"foodPerDayUsd":75,"activitiesPerDayUsd":35}'::jsonb, ARRAY['spring', 'summer', 'fall']::text[], NULL),
  ('acadia-np', 'Acadia National Park', 'Coastal Maine', 'ME', 44.3386, -68.2733, ARRAY['nature', 'scenic', 'adventure']::text[], 'Pink-granite headlands meeting the Atlantic — the only fjord on the eastern seaboard, with a side of lobster rolls.', NULL, '[{"name":"Cadillac Mountain","description":"Highest point on the US Atlantic — first US sunrise Oct–Mar."},{"name":"Jordan Pond Path","description":"3.3-mile loop with popovers at the end."},{"name":"Bar Harbor","description":"Walkable base town for the park; ferries to Schoodic Peninsula."}]'::jsonb, '{"flightFromOrigin":{"NYC":240,"CHI":320,"LAX":480,"SFO":480,"SEA":460},"lodgingPerNightUsd":240,"foodPerDayUsd":75,"activitiesPerDayUsd":25}'::jsonb, ARRAY['summer', 'fall']::text[], NULL),
