  ('yosemite-np', 'Yosemite National Park', 'Sierra Nevada', 'CA', 37.8651, -119.5383, ARRAY['nature', 'adventure', 'scenic']::text[], 'Granite cathedrals, 2,400-ft waterfalls, and giant sequoias — the most iconic vertical landscape in America.', NULL, '[{"name":"Tunnel View","description":"First arrival shot — El Cap, Half Dome, Bridalveil all in one frame."},{"name":"Glacier Point","description":"Drive-up overlook; sunset on Half Dome''s north face."},{"name":"Mist Trail","description":"Climbs alongside Vernal and Nevada Falls — wet in spring."}]'::jsonb, '{"flightFromOrigin":{"NYC":320,"CHI":280,"LAX":200,"SFO":160,"SEA":240},"lodgingPerNightUsd":260,"foodPerDayUsd":65,"activitiesPerDayUsd":25}'::jsonb, ARRAY['spring', 'summer', 'fall']::text[], NULL),
  ('zion-np', 'Zion National Park', 'Colorado Plateau', 'UT', 37.2982, -113.0263, ARRAY['nature', 'adventure', 'scenic']::text[], 'Vermillion canyon walls and the Virgin River cutting through them — slot canyons and Angels Landing.', NULL, '[{"name":"Angels Landing","description":"5-mile out-and-back; chained-cliff section is unforgettable. Permit required."},{"name":"The Narrows","description":"Wading the Virgin River through a slot canyon — rent neoprene in spring."},{"name":"Springdale","description":"Walkable gateway town with the shuttle terminus."}]'::jsonb, '{"flightFromOrigin":{"NYC":320,"CHI":260,"LAX":180,"SFO":220,"SEA":260},"lodgingPerNightUsd":250,"foodPerDayUsd":65,"activitiesPerDayUsd":30}'::jsonb, ARRAY['spring', 'fall']::text[], NULL),
